// src/AddTicket.jsx
import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API_BASE = "https://prasa-app-yde3.onrender.com/api/app";

export default function AddTicket({ employee }) {
  const navigate = useNavigate();

  const [ticketDate, setTicketDate] = useState("");
  const [purpose, setPurpose] = useState("");
  const [assignedTo, setAssignedTo] = useState("");
  const [amount, setAmount] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      empId: employee.empld,
      ticket_date: ticketDate,
      purpose,
      assigned_to: assignedTo,
      amount,
    };

    try {
      const res = await axios.post(`${API_BASE}/add-ticket`, payload);
      if (res.data.success) {
        alert("Ticket expense saved!");
        setTicketDate("");
        setPurpose("");
        setAssignedTo("");
        setAmount("");
      } else {
        alert("Failed to save ticket");
      }
    } catch (err) {
      console.error("AddTicket error:", err);
      alert("Server error while saving ticket");
    }
  };

  const green = "#0f9d58";
  const light = "#eaf8f0";

  return (
    <div
      style={{
        background: light,
        minHeight: "100vh",
        padding: 20,
        display: "flex",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: 780,
          background: "#fff",
          borderRadius: 18,
          padding: 20,
          boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            onClick={() => navigate("/addnew")}
            style={{
              background: light,
              border: "none",
              padding: "8px 12px",
              borderRadius: 10,
              cursor: "pointer",
            }}
          >
            ←
          </button>
          <h2 style={{ margin: 0, color: green }}>Add Ticket Expense</h2>
        </div>

        <p style={{ marginTop: 8, color: "#555" }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        <form onSubmit={handleSubmit} style={{ marginTop: 15 }}>
          <div style={{ marginBottom: 10 }}>
            <label>Date</label>
            <input
              type="date"
              value={ticketDate}
              onChange={(e) => setTicketDate(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
              required
            />
          </div>

          <div style={{ marginBottom: 10 }}>
            <label>Purpose</label>
            <input
              type="text"
              value={purpose}
              onChange={(e) => setPurpose(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <div style={{ marginBottom: 10 }}>
            <label>Assigned To</label>
            <input
              type="text"
              value={assignedTo}
              onChange={(e) => setAssignedTo(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <div style={{ marginBottom: 16 }}>
            <label>Amount</label>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <button
            type="submit"
            style={{
              width: "100%",
              background: green,
              color: "#fff",
              border: "none",
              borderRadius: 10,
              padding: 12,
              cursor: "pointer",
              fontSize: 16,
            }}
          >
            Save Ticket
          </button>
        </form>
      </div>
    </div>
  );
}
